from matplotlib import pyplot as pltfrom skimage.filters import gaussianfrom skimage import img_as_ubyteimport cv2import globimport ospath  = "../data/scratch_assay/*.*"img_number = 1for file in glob.glob(path):    print(file)    img = cv2.imread(file,0)    smoothed_img = img_as_ubyte(gaussian(img, sigma = 5, mode = "constant", cval = 0.0))    cv2.imwrite("../data/smoothed_scratch_assay/smoothed_"+str(img_number)+".jpg", smoothed_img)    img_number+=1